sys_script_include.script:
var DecisionParser = Class.create();
DecisionParser.prototype = {
	_decision: "",
    _entries: [],

    DEFAULT_HELPER: function(questions, includeDefaultAnswer = false) {
        var entries = questions.result; // array
        if (!includeDefaultAnswer) entries = entries.filter(e => e.defaultAnswer == false);

        entries = entries.map(function(e) {
            // The question has a 'answer.valid' property, and we treat that
            // as our 'valid' for now. May override later.

            // In a few cases, answer.valid is false, such as if the 
            // referenced location has been deleted. We do not get a 
            // message saying what the problem is, so we do not set message here.
            var obj = {
                "valid": e.answer.valid,
                "location": "",
                "message": ""
            };

            // In a few cases we will set valid to false for other reasons.

            // Ex: "condition": "u_location=54^EQ",
            obj.location = e.condition == "" ? "" : e.condition.split("=")[1].split("^")[0].trim();

            // reference comes from question.answer.answerElementValues. This might be an empty array.
            if (e.answer.answerElementValues.length > 0) {
                obj['reference'] = {
                    "label": e.answer.answerElementValues[0].label,
                    "value": e.answer.answerElementValues[0].value
                };
            } else {
                obj.valid = false;
                obj.message = "No Location";
            }
            return obj;
        });

        // If any object has no reference, mark it invalid
        entries
            .filter(function(e) {
                return e.valid && !Object.hasOwn(e, 'reference');
            })
            .forEach(function(e) {
                e.valid = false;
                e.message = "no valid result";
            });


        // If any entry has a blank location, mark it invalid
        entries
            .filter(function(e) {
                return e.valid && e.location.length == 0;
            })
            .forEach(function(e) {
                e.valid = false;
                e.message = "no location";
            });

        // Get all the locations, check for duplicates, mark invalid
        // any entry having one of these
        var locations = [];
        entries
            .filter(function(e) {
                return e.location.length > 0;
            })
            .forEach(function(e) {
                locations.push(e.location);
            });
        entries
            .filter(function(e) {
                return e.valid == true;
            })
            .forEach(function(e) {
                if (locations.indexOf(e.location) != locations.lastIndexOf(e.location)) {
                    e.valid = false;
                    e.message = "Duplicate location";
                }
            });

        return entries;
    },

    Filter: {
        ALL: 0,
        VALID: 1,
        INVALID: 2
    },

    initialize: function(decisionTableName) {
        var gr_decision = new GlideRecord("sys_decision");
        gr_decision.addQuery("name", decisionTableName);
        gr_decision.setLimit(1);
        gr_decision.query();
        gr_decision.next();
        this._decision = gr_decision.getValue("sys_id");
    },

    getEntries: function(helper) {
        var dt = new sn_dt.DecisionTableAPI();
        var questions = dt.getQuestions(this._decision);
		return helper(questions);
    },

    type: 'DecisionParser'
};
